import React, { useState } from 'react';
import { generateLegalDoc } from '../services/geminiService';
import { FileText, Loader2, Copy, Check } from 'lucide-react';

const LegalDocGenerator: React.FC = () => {
  const [docType, setDocType] = useState('Đơn đề nghị giãn nợ');
  const [details, setDetails] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    if (!details.trim()) return;
    setLoading(true);
    setCopied(false);
    try {
      const text = await generateLegalDoc(docType, details);
      setResult(text);
    } catch (error) {
      console.error(error);
      setResult("Có lỗi xảy ra, vui lòng thử lại.");
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(result);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="max-w-4xl mx-auto">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-slate-900 flex items-center justify-center gap-3">
            <FileText className="text-blue-600" /> Cá nhân hóa Văn Bản Pháp Lý
          </h1>
          <p className="text-slate-600 mt-2">Tạo văn bản chuyên nghiệp chỉ trong vài giây để làm việc với ngân hàng.</p>
        </div>

        <div className="grid md:grid-cols-2 gap-8">
          {/* Input Section */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Loại văn bản</label>
                <select 
                  value={docType}
                  onChange={(e) => setDocType(e.target.value)}
                  className="w-full rounded-lg border-slate-300 border p-2.5 focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="Đơn đề nghị giãn nợ">Đơn đề nghị giãn nợ</option>
                  <option value="Đơn tố giác tội phạm có dấu hiệu cưỡng đoạt tài sản">Đơn tố giác tội phạm (Cưỡng đoạt tài sản)</option>
                  <option value="Đơn đề nghị miễn giảm lãi phạt">Đơn đề nghị miễn giảm lãi phạt</option>
                  <option value="Đơn tố giác hành vi bôi nhọ danh dự">Đơn tố giác hành vi bôi nhọ danh dự</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Chi tiết tình huống</label>
                <textarea 
                  value={details}
                  onChange={(e) => setDetails(e.target.value)}
                  rows={8}
                  placeholder="Ví dụ: Tôi tên là Nguyễn Văn A, nợ thẻ tín dụng ngân hàng X. Hiện tại tôi bị các đối tượng gọi điện đe dọa sẽ giết hại người thân, gửi ảnh ghép đồi trụy nếu không thanh toán trong 1 giờ..."
                  className="w-full rounded-lg border-slate-300 border p-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm"
                ></textarea>
                <p className="text-xs text-slate-500 mt-1">Càng chi tiết về hành vi đe dọa, văn bản càng có sức thuyết phục và tính pháp lý cao.</p>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={loading || !details}
                className="w-full py-3 px-4 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white font-semibold rounded-lg transition-colors flex items-center justify-center gap-2"
              >
                {loading ? <Loader2 className="animate-spin w-5 h-5" /> : "Soạn thảo ngay"}
              </button>
            </div>
          </div>

          {/* Output Section */}
          <div className="bg-slate-50 p-6 rounded-xl border border-slate-200 relative min-h-[400px]">
            {result ? (
              <>
                <div className="absolute top-4 right-4">
                  <button 
                    onClick={copyToClipboard}
                    className="p-2 text-slate-500 hover:text-blue-600 hover:bg-blue-50 rounded-md transition-all"
                    title="Copy"
                  >
                    {copied ? <Check className="w-5 h-5 text-green-600" /> : <Copy className="w-5 h-5" />}
                  </button>
                </div>
                <div className="prose prose-slate max-w-none whitespace-pre-wrap text-sm font-serif leading-relaxed">
                  {result}
                </div>
              </>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-400">
                <FileText className="w-12 h-12 mb-2 opacity-20" />
                <p>Văn bản của bạn sẽ xuất hiện ở đây</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default LegalDocGenerator;
